import { Card, Typography, Grid, Stack, Divider } from "@mui/material";
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import {Link} from 'react-router-dom'

function LessonCard(props) {
    return (
        <Grid item xs={3}>
            <Link to={props.courseURL || '404'} style={{color:'inherit', textDecoration:'none'}}>
                <Card style={{padding:'5px'}} elevation={6}>
                    <Typography variant="h6">
                        {props.name || 'Nommez-moi SVP !'}
                    </Typography>
                    <Divider style={{marginBottom:'10px'}}/>
                    <Typography variant="body1">
                        {props.description || 'Décrivez-mois SVP !'}
                    </Typography>

                    <Stack direction='row' spacing={1}>
                        <AccessTimeIcon />
                        <Typography variant="body2">
                            {props.time || 'Temps inconnus'}
                        </Typography>

                    </Stack>
                </Card>
            </Link>
        </Grid>
    )
}

export default LessonCard;