import { Grid } from "@mui/material";
import CourseSelection from "../components/CourseSelection";
import Header from '../components/Header'
import React from "react";

function Home() {
    return (
        <React.Fragment>
            <Header />
            <Grid container spacing={3}>
                <Grid item xs={3}>
                    <CourseSelection />
                </Grid>
                <Grid item xs={9}>
                    Hellow !
                </Grid>
            </Grid>
        </React.Fragment>
    )
}

export default Home;