import { Fragment, useState, useEffect } from "react";
import Header from "../components/Header";
import { useParams } from "react-router-dom";
import courses from "../courses";
import ReactMarkdown from 'react-markdown'
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter'
import { dark } from 'react-syntax-highlighter/dist/esm/styles/prism'

function CourseContent() {
    let { courseUrl, lessonUrl } = useParams()
    let lesson = courses.find(c => c.url === courseUrl).lessons.find(l => l.lessonURL === lessonUrl)
    const [content, setContent] = useState(0)

    useEffect(() => {
        console.log('../static/courses/' + courseUrl + '/' + lessonUrl + '.md')
        const file = require('../static/courses/' + courseUrl + '/' + lessonUrl + '.md')

        const fetchFile = async () => {
            const fileContent = await (
                await fetch(file)
            ).text()

            setContent(fileContent)
        }

        fetchFile()
        /*fetch(file)
            .then(response => response.text())
            .then(text => setContent(text))*/
    }, [])

    return (
        <Fragment>
            <Header title={lesson.title} />
            <ReactMarkdown children={content}
                // Copier de https://github.com/remarkjs/react-markdown#use-custom-components-syntax-highlight
                components={{
                    code({ node, inline, className, children, ...props }) {
                        const match = /language-(\w+)/.exec(className || '')
                        return !inline && match ? (
                            <SyntaxHighlighter
                                {...props}
                                children={String(children).replace(/\n$/, '')}
                                style={dark}
                                language={match[1]}
                                PreTag="div"
                            />
                        ) : (
                            <code {...props} className={className}>
                                {children}
                            </code>
                        )
                    }
                }} />
        </Fragment>
    )
}

export default CourseContent;