import LessonCard from '../components/LessonCard'
import Header from '../components/Header'
import { Grid } from '@mui/material';
import React from 'react';
import { useParams } from 'react-router-dom';

import courses from '../courses';

function CourseIndex() {
    let { courseUrl } = useParams()
    let element = courses.find(e => e.url === courseUrl)

    return (
        <React.Fragment>
            <Header title={element.title} />
            <Grid container spacing={2}>
                {element.lessons.map(lesson => (<LessonCard key={lesson.lessonURL} name={lesson.name} description={lesson.description}
                    time={lesson.time} courseURL={lesson.lessonURL} />))}
            </Grid>
        </React.Fragment>
    )
}

export default CourseIndex;